class Solution:
    def minimumTime(self, s: str) -> int:
        n = len(s)
        prefix = [0] * (n + 1)
        for i, ch in enumerate(s):
            prefix[i + 1] = prefix[i] + (1 if ch == '1' else 0)
        best = None
        for l in range(n + 1):
            for r in range(n - l + 1):
                mid_ones = prefix[n - r] - prefix[l]
                cost = l + r + 2 * mid_ones
                if best is None or cost < best:
                    best = cost
        return best

