class Solution:
    def minimumTime(self, s: str) -> int:
        n = len(s)
        dp = [0] * (n + 1)
        for i in range(n):
            dp[i + 1] = min(dp[i] + (2 if s[i] == '1' else 0), i + 1)
        ans = dp[n]
        for i in range(n + 1):
            ans = min(ans, dp[i] + (n - i))
        return ans

