var minimumTime = function(s) {
    const n = s.length;
    const dp = new Array(n + 1).fill(0);
    for (let i = 0; i < n; i++) {
        dp[i + 1] = Math.min(dp[i] + (s[i] === '1' ? 2 : 0), i + 1);
    }
    let ans = dp[n];
    for (let i = 0; i <= n; i++) {
        ans = Math.min(ans, dp[i] + (n - i));
    }
    return ans;
};
